mapper.select:

WHERE s.session_date BETWEEN #{from} AND #{to}
  AND s.status = 'OPEN'
ORDER BY s.session_date, s.start_time, t.table_number

mapper.update:
UPDATE sessions
SET status        = 'CANCELLED',
    cancel_reason = #{cancelReason}
WHERE id = #{id}

mapper.select:

WHERE s.status        = 'OPEN'
  AND s.reminder_sent = FALSE
  AND s.session_date  = #{date}
  AND s.start_time    BETWEEN #{minTime} AND #{maxTime}
ORDER BY s.start_time, t.table_number

SELECT COUNT(*) > 0
FROM sessions
WHERE session_date = #{date}
  AND start_time   = #{time}
  AND status       = 'OPEN'

SELECT id
FROM sessions
WHERE session_date = #{date}
  AND start_time   = #{time}
  AND status       = 'OPEN'
LIMIT 1
